import os
from tensorflow_serving.apis import predict_pb2, service as predict_service_pb
from grpc import insecure_channel

def get_latest_model(bucket_name):
    import google.cloud.storage as storage
    client = storage.Client()
    blobs = client.list_blobs('{}-versions'.format(bucket_name))
    sorted_blobs = sorted(blobs, reverse=True, key=lambda x: int(x.name.split('-')[-1]))
    return sorted_blobs[0].name

def load_model(model_path):
    channel = insecure_channel(model_path)
    stub = predict_service_pb.PredictServiceStub(channel)
    request = predict_pb2.PredictRequest()
    response = stub.Predict(request)
    return response

def main():
    model_bucket = os.environ['MODEL_PATH']
    latest_model = get_latest_model(model_bucket)
    model_path = '{}-v{}'.format(model_bucket, latest_model)
    load_model(model_path)

if __name__ == "__main__":
    main()